      const { x1: bx1, y1: by1, x2: bx2, y2: by2 } = parseKey(keyB);
      const b1 = islands.find((i) => i.x === bx1 && i.y === by1);
      const b2 = islands.find((i) => i.x === bx2 && i.y === by2);
      if (!b1 || !b2) continue;

      // if share endpoints, ignore
      const sharesEndpoint =
        (a1.id === b1.id || a1.id === b2.id || a2.id === b1.id || a2.id === b2.id);
      if (sharesEndpoint) continue;

      const segB = segmentFromIslands(b1, b2);
      if (segmentsCross(segA, segB)) return false;
    }
  }

  return checkConnectivity(islands, bridges);
}

export const ERROR_MESSAGES = {
  ERR_NON_ADJ,
  ERR_MAX_PAIR,
  ERR_EXCEED,
  ERR_CROSS
};
