import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles, puzzleOptions } from './data/puzzles.js';
import {
  canAddBridge,
  canonicalKey,
  computeCurrentCounts,
  isVictory
} from './utils/hashiLogic.js';

const GRID = 40;
const WIDTH = 800;
const HEIGHT = 600;

function findIslandById(islands, id) {
  return islands.find((i) => i.id === id) ?? null;
}

function findNearestIslandInDirection(islands, from, dir) {
  if (!from) return islands[0] ?? null;

  let best = null;
  let bestDist = Infinity;

  for (const isl of islands) {
    if (isl.id === from.id) continue;

    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      const d = from.x - isl.x;
      if (d < bestDist) {
        bestDist = d;
        best = isl;
      }
    } else if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      const d = isl.x - from.x;
      if (d < bestDist) {
        bestDist = d;
        best = isl;
      }
    } else if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      const d = from.y - isl.y;
      if (d < bestDist) {
        bestDist = d;
        best = isl;
      }
    } else if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      const d = isl.y - from.y;
      if (d < bestDist) {
        bestDist = d;
        best = isl;
      }
    }
  }

  return best;
}

function keyToEndpoints(key) {
  const [x1, y1, x2, y2] = key.split(',').map((n) => Number(n));
  return { x1, y1, x2, y2 };
}

function bridgeHitTest(bridgeKey, px, py) {
  // Detect clicks near the visible line(s). Keep simple: distance to segment <= 6.
  const { x1, y1, x2, y2 } = keyToEndpoints(bridgeKey);
  const ax = x1 * GRID;
  const ay = y1 * GRID;
  const bx = x2 * GRID;
  const by = y2 * GRID;

  const tol = 6;
  if (ax === bx) {
    // vertical
    const minY = Math.min(ay, by);
    const maxY = Math.max(ay, by);
    return Math.abs(px - ax) <= tol && py >= minY && py <= maxY;
  }
  // horizontal
  const minX = Math.min(ax, bx);
  const maxX = Math.max(ax, bx);
  return Math.abs(py - ay) <= tol && px >= minX && px <= maxX;
}

export default function App() {
  const [puzzleKey, setPuzzleKey] = useState('easy');
  const islands = useMemo(() => puzzles[puzzleKey].islands, [puzzleKey]);

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null);
  const [cursorId, setCursorId] = useState(0);
  const [kbFromId, setKbFromId] = useState(null);
  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  useEffect(() => {
    // On puzzle change: reset everything (bridges + selections)
    setBridges(new Map());
    setSelectedId(null);
    setKbFromId(null);
    setError(null);
    setCursorId(islands[0]?.id ?? 0);
  }, [puzzleKey]); // eslint-disable-line react-hooks/exhaustive-deps

  function clearErrorOnValidMove(result) {
    if (result?.valid) setError(null);
  }

  function applyBridgeDelta(from, to, delta) {
    const res = canAddBridge(islands, bridges, from, to, delta);
    if (!res.valid) {
      setError(res.error);
      return;
    }

    const key = canonicalKey(from, to);
    const current = bridges.get(key) ?? 0;
    const next = Math.max(0, Math.min(2, current + delta));

    const nextMap = new Map(bridges);
    if (next === 0) nextMap.delete(key);
    else nextMap.set(key, next);

    setBridges(nextMap);
    clearErrorOnValidMove(res);
  }

  function cycleBridge(from, to) {
    const key = canonicalKey(from, to);
    const current = bridges.get(key) ?? 0;
    const desired = current === 0 ? 1 : current === 1 ? 2 : 0;
    const delta = desired - current;
    if (delta === 0) return;

    if (desired === 0) {
      // always allowed
      const nextMap = new Map(bridges);
      nextMap.delete(key);
      setBridges(nextMap);
      setError(null);
      return;
    }

    applyBridgeDelta(from, to, delta);
  }

  function handleIslandClick(isl) {
    if (selectedId == null) {
      setSelectedId(isl.id);
      setKbFromId(null);
      setCursorId(isl.id);
      return;
    }

    if (selectedId === isl.id) {
      // keep selection
      return;
    }

    const from = findIslandById(islands, selectedId);
    const to = isl;
    cycleBridge(from, to);
    setSelectedId(null);
  }

  function removeBridgeByKey(key) {
    if (!bridges.has(key)) return;
    const nextMap = new Map(bridges);
    nextMap.delete(key);
    setBridges(nextMap);
    setError(null);
  }

  function handleSvgPointerDown(e) {
    // Right click or ctrl+click on existing bridge removes it.
    if (!(e.button === 2 || e.ctrlKey)) return;
    e.preventDefault();

    const svg = svgRef.current;
    if (!svg) return;
    const pt = svg.createSVGPoint();
    pt.x = e.clientX;
    pt.y = e.clientY;
    const ctm = svg.getScreenCTM();
    if (!ctm) return;
    const loc = pt.matrixTransform(ctm.inverse());

    for (const [key] of bridges.entries()) {
      if (bridgeHitTest(key, loc.x, loc.y)) {
