        setKbFromId(null);
        setSelectedId(null);
        return;
      }

      const dir =
        e.key === 'ArrowLeft' ? 'left' :
        e.key === 'ArrowRight' ? 'right' :
        e.key === 'ArrowUp' ? 'up' :
        e.key === 'ArrowDown' ? 'down' :
        null;

      if (dir) {
        e.preventDefault();
        const next = findNearestIslandInDirection(islands, cur, dir);
        if (next) setCursorId(next.id);
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        if (kbFromId == null) {
          setKbFromId(cursorId);
          setSelectedId(null);
          return;
