  const kbFromIsland = findIslandById(islands, kbFromId);

  return (
    <div className="app">
      <div className="hud">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleKey}
            onChange={(e) => setPuzzleKey(e.target.value)}
            aria-label="Puzzle"
          >
