export function segmentFromIslands(a, b) {
  const horiz = a.y === b.y;
  if (horiz) {
    const x1 = Math.min(a.x, b.x);
    const x2 = Math.max(a.x, b.x);
    return { orient: 'h', x1, x2, y: a.y };
  }
  const y1 = Math.min(a.y, b.y);
  const y2 = Math.max(a.y, b.y);
  return { orient: 'v', y1, y2, x: a.x };
